+export function chunkText(input: string) {
+  const normalized = input.replace(/\s+/g, " ").trim();
+  if (!normalized) return [];
+
+  const chunks: string[] = [];
+  let index = 0;
+
+  while (index < normalized.length) {
+    const end = Math.min(index + LIMITS.maxChunkCharacters, normalized.length);
+    let sliceEnd = end;
+
+    if (end < normalized.length) {
+      const punctuation = normalized.lastIndexOf(".", end);
+      if (punctuation > index + LIMITS.maxChunkCharacters * 0.55) {
+        sliceEnd = punctuation + 1;
+      }
+    }
+
+    chunks.push(normalized.slice(index, sliceEnd).trim());
+    if (sliceEnd >= normalized.length) break;
+    index = Math.max(0, sliceEnd - LIMITS.chunkOverlapCharacters);
+  }
+
+  return chunks.filter(Boolean);
+}
+
+export function estimateBytes(value: string) {
+  return new TextEncoder().encode(value).byteLength;
