+export function rankChunksByKeywords(question: string, chunks: MaterialChunk[], count = 5) {
+  const questionTokens = tokenize(question);
+  return chunks
+    .map((chunk) => {
+      const chunkTokens = tokenize(chunk.content);
+      let overlap = 0;
+      questionTokens.forEach((token) => {
+        if (chunkTokens.has(token)) overlap += 1;
+      });
+      return {
+        ...chunk,
+        similarity: questionTokens.size ? overlap / questionTokens.size : 0
+      };
+    })
+    .sort((a, b) => (b.similarity ?? 0) - (a.similarity ?? 0))
+    .slice(0, count);
