+  if (!shouldUseSupabase()) {
+    const material: Material = {
+      id: createId("material"),
+      class_id: input.classId,
+      title: input.title,
+      type: input.type,
+      content: input.content,
+      metadata: {},
+      storage_bytes: storageBytes,
+      created_at: now()
+    };
+    mockMaterials.unshift(material);
+    mockChunks = [
+      ...chunks.map((content, chunkIndex) => ({
+        id: createId("chunk"),
+        material_id: material.id,
+        class_id: input.classId,
+        content,
+        chunk_index: chunkIndex,
+        metadata: { title: material.title }
+      })),
+      ...mockChunks
+    ];
+    return { material, chunks: chunks.length };
+  }
+
+  const supabase = createServiceSupabaseClient();
+  const { data: material, error: materialError } = await supabase!
+    .from("materials")
+    .insert({
+      class_id: input.classId,
+      title: input.title,
+      type: input.type,
+      content: input.content,
+      metadata: {},
+      storage_bytes: storageBytes
+    })
+    .select("*")
+    .single();
+
+  if (materialError) throw materialError;
+
+  const rows = [];
+  for (let index = 0; index < chunks.length; index += 1) {
+    rows.push({
+      material_id: material.id,
+      class_id: input.classId,
+      content: chunks[index],
+      chunk_index: index,
+      metadata: { title: input.title },
+      embedding: await embedText(chunks[index])
+    });
+  }
+
+  const { error: chunkError } = await supabase!.from("material_chunks").insert(rows);
+  if (chunkError) throw chunkError;
+
+  return { material: material as Material, chunks: chunks.length };
+}
+
+export async function retrieveChunks(classId: string, question: string) {
+  if (!shouldUseSupabase() || !process.env.OPENAI_API_KEY) {
+    return rankChunksByKeywords(
+      question,
+      mockChunks.filter((chunk) => chunk.class_id === classId)
+    );
+  }
+
+  const supabase = createServiceSupabaseClient();
+  const embedding = await embedText(question);
+  const { data, error } = await supabase!.rpc("match_materials", {
+    query_embedding: embedding,
+    match_threshold: 0.2,
+    match_count: 5,
+    p_class_id: classId
+  });
+
+  if (error) throw error;
+  return (data || []) as MaterialChunk[];
