+import { useEffect, useMemo, useState } from "react";
+import Link from "next/link";
+import { ArrowLeft, Send } from "lucide-react";
+import { LIMITS, STORAGE_KEYS } from "@/lib/constants";
+import { canSendMessage, loadMessages, readJson, touchClassVisit, writeJson } from "@/lib/student-session";
+import type { ChatMessage, ChatSource, Classroom } from "@/lib/types";
+import { createId } from "@/lib/utils";
+
+export function ChatWindow({ slug }: { slug: string }) {
+  const [classroom, setClassroom] = useState<Classroom | null>(null);
+  const [messages, setMessages] = useState<ChatMessage[]>([]);
+  const [input, setInput] = useState("");
+  const [error, setError] = useState("");
+  const [loading, setLoading] = useState(true);
+  const [sending, setSending] = useState(false);
+
+  const lastVisitedKey = useMemo(() => (classroom ? STORAGE_KEYS.visited(classroom.id) : ""), [classroom]);
+
+  useEffect(() => {
+    fetch(`/api/classes/by-slug/${slug}`)
+      .then((response) => response.json())
+      .then((payload) => {
+        if (!payload.classroom) {
+          setError("Class not found.");
+          return;
+        }
+        const found = payload.classroom as Classroom;
+        setClassroom(found);
+        const lastVisited = window.localStorage.getItem(STORAGE_KEYS.visited(found.id));
+        const restored = loadMessages(found.id, lastVisited);
+        setMessages(
+          restored.length
+            ? restored
+            : [
+                {
+                  id: createId("msg"),
+                  role: "assistant",
+                  content: `Hey there. I am your Askfree tutor for ${found.name}. Ask me anything from the uploaded class materials.`,
+                  createdAt: new Date().toISOString()
+                }
+              ]
+        );
+        const visit = { classId: found.id, slug: found.slug, name: found.name, lastVisited: new Date().toISOString() };
+        touchClassVisit(visit);
+        window.localStorage.setItem(STORAGE_KEYS.visited(found.id), visit.lastVisited);
+      })
+      .finally(() => setLoading(false));
+  }, [slug]);
+
+  useEffect(() => {
+    if (!classroom) return;
+    writeJson(STORAGE_KEYS.chat(classroom.id), messages);
+  }, [classroom, messages]);
+
+  async function send() {
+    if (!classroom || !input.trim() || sending) return;
+    setError("");
+    const quota = canSendMessage(readJson<string[]>(STORAGE_KEYS.quota(classroom.id), []));
+    if (!quota.allowed) {
+      setError(`You have reached ${LIMITS.studentMessagesPerHour} messages for this hour. Take a breather and try again soon.`);
+      return;
+    }
+
+    const question = input.trim();
+    const userMessage: ChatMessage = {
+      id: createId("msg"),
+      role: "user",
+      content: question,
+      createdAt: new Date().toISOString()
+    };
+    setMessages((current) => [...current, userMessage]);
+    setInput("");
+    setSending(true);
+
+    const response = await fetch("/api/chat", {
+      method: "POST",
+      headers: { "Content-Type": "application/json" },
+      body: JSON.stringify({ classId: classroom.id, question })
+    });
+    const payload = (await response.json()) as { answer?: string; sources?: ChatSource[]; error?: string };
+    setSending(false);
+    if (!response.ok) {
+      setError(payload.error || "Could not answer that question.");
+      return;
+    }
+
+    const assistantMessage: ChatMessage = {
+      id: createId("msg"),
+      role: "assistant",
+      content: payload.answer || "",
+      sources: payload.sources || [],
+      createdAt: new Date().toISOString()
+    };
+    setMessages((current) => [...current, assistantMessage]);
+    const recent = [...quota.recent, new Date().toISOString()];
+    writeJson(STORAGE_KEYS.quota(classroom.id), recent);
+    window.localStorage.setItem(lastVisitedKey, new Date().toISOString());
+  }
+
+  if (loading) return <main className="af-container py-12 text-warm-muted">Opening classroom...</main>;
+
+  if (!classroom) {
+    return (
+      <main className="af-container py-12">
+        <div className="af-card p-8">{error || "Class not found."}</div>
+      </main>
+    );
+  }
+
+  return (
+    <main className="flex min-h-screen flex-col bg-warm-bg">
+      <header className="sticky top-0 z-20 border-b border-warm-border bg-warm-surface/90 backdrop-blur">
+        <div className="af-container flex h-16 items-center justify-between">
+          <Link href="/" className="inline-flex items-center gap-2 font-semibold text-warm-accent">
+            <ArrowLeft size={18} /> Home
+          </Link>
+          <h1 className="font-display text-xl font-semibold">{classroom.name}</h1>
+          <span className="w-16" />
+        </div>
+      </header>
+
+      <section className="af-container flex max-w-4xl flex-1 flex-col gap-4 py-8">
+        {messages.map((message) => (
+          <article
+            key={message.id}
+            className={
+              message.role === "user"
+                ? "ml-auto max-w-[86%] rounded-3xl rounded-br-md bg-warm-accent p-4 font-semibold text-white"
+                : "max-w-[90%] rounded-3xl rounded-bl-md border border-warm-border bg-warm-surface p-4 shadow-soft"
+            }
+          >
+            <p className="whitespace-pre-wrap">{message.content}</p>
+            {message.sources?.length ? (
+              <div className="mt-4 space-y-2 border-t border-warm-border pt-3 text-sm text-warm-muted">
+                {message.sources.map((source, index) => (
+                  <p key={`${source.title}-${index}`}>
+                    <strong>{source.title}:</strong> {source.excerpt}
+                  </p>
+                ))}
+              </div>
+            ) : null}
+          </article>
+        ))}
+        {sending ? <div className="max-w-fit rounded-3xl border border-warm-border bg-warm-surface p-4 text-warm-muted">Thinking from the notes...</div> : null}
+      </section>
+
+      <footer className="sticky bottom-0 border-t border-warm-border bg-warm-surface p-4">
+        <div className="af-container max-w-4xl">
+          {error ? <p className="mb-3 rounded-2xl bg-red-50 p-3 text-sm text-red-700">{error}</p> : null}
+          <div className="flex gap-3">
+            <input
+              className="af-input"
+              value={input}
+              onChange={(event) => setInput(event.target.value)}
+              onKeyDown={(event) => {
+                if (event.key === "Enter") void send();
+              }}
+              placeholder="Ask your class tutor anything..."
+            />
+            <button className="af-button-primary aspect-square px-4" onClick={() => void send()} disabled={sending}>
+              <Send size={18} />
+            </button>
+          </div>
+        </div>
+      </footer>
+    </main>
+  );
+}
